10	import { useThemeStore } from '@/store/useThemeStore';
11	
12	const FIVE_MINUTES_MS = 5 * 60 * 1000;
13	
14	const ThemeBootstrap = () => {
15	    const theme = useThemeStore((state) => state.theme);
16	
17	    useEffect(() => {
18	        document.documentElement.classList.toggle('dark', theme === 'dark');
19	    }, [theme]);
20	
21	    return null;
22	};
23	
24	const AuthBootstrap = ({ onReady }) => {
25	    const setUser = useAuthStore((state) => state.setUser);
26	    const logout = useAuthStore((state) => state.logout);
27	
28	    useEffect(() => {
29	        if (window.location.pathname === '/login') {
30	            onReady();
31	            return;
32	        }
33	
34	        let cancelled = false;
35	
36	        getMe()
37	            .then((user) => {
38	                if (!cancelled) {
39	                    setUser(user);
40	                    onReady();
41	                }
42	            })
43	            .catch(() => {
44	                if (!cancelled) {
45	                    logout();
46	                    onReady();
47	                }
48	            });
49	
50	        return () => {
51	            cancelled = true;
52	        };
53	    }, [logout, onReady, setUser]);
54	
55	    return null;
56	};
57	
58	setUnauthorizedHandler(() => {
59	    useAuthStore.getState().logout();
60	});
61	
62	export const Providers = () => {
63	    const [authReady, setAuthReady] = useState(false);
64	    const handleAuthReady = useCallback(() => {
65	        setAuthReady(true);
66	    }, []);
67	    const [queryClient] = useState(
68	        () =>
69	            new QueryClient({
70	                defaultOptions: {
71	                    queries: {
72	                        retry: 1,
73	                        staleTime: FIVE_MINUTES_MS,
74	                    },
75	                },
76	            }),
77	    );
78	
79	    return (
80	        <QueryClientProvider client={queryClient}>
81	            <ThemeBootstrap />
82	            <AuthBootstrap onReady={handleAuthReady} />
83	            <AuthReadyContext value={authReady}>
84	                <RouterProvider router={router} />
85	            </AuthReadyContext>
86	            <Toaster richColors position="top-right" />
87	        </QueryClientProvider>
88	    );
89	};
