5	const DEFAULT_DETAIL_CACHE_TIME_MS = 5 * 60 * 1000;
6	
7	export const useListPage = ({
8	    listQueryKey,
9	    listUrl,
10	    detailQueryKey,
11	    detailUrl,
12	    initialRequest,
13	    detailCacheTimeMs = DEFAULT_DETAIL_CACHE_TIME_MS,
14	}) => {
15	    const [request, setRequest] = useState(initialRequest);
16	    const [selectedId, setSelectedId] = useState(null);
17	    const isDetailOpen = selectedId !== null && selectedId !== undefined;
18	
19	    const pageQuery = useQuery({
20	        queryKey: [listQueryKey, request],
21	        queryFn: ({ signal }) =>
22	            requestJson({
23	                method: 'post',
24	                url: listUrl,
25	                data: request,
26	                signal,
27	            }),
28	    });
29	
30	    const detailQuery = useQuery({
31	        queryKey: [detailQueryKey, selectedId],
32	        queryFn: ({ signal }) =>
33	            requestJson({
34	                method: 'get',
35	                url: `${detailUrl}/${selectedId}`,
36	                signal,
37	            }),
38	        enabled: isDetailOpen,
39	        staleTime: detailCacheTimeMs,
40	        gcTime: detailCacheTimeMs,
41	    });
42	
43	    return {
44	        request,
45	        setRequest,
46	        selectedId,
47	        setSelectedId,
48	        isDetailOpen,
49	        pageQuery,
50	        detailQuery,
51	    };
52	};
