1	import axios from 'axios';
2	
3	export const axiosInstance = axios.create({
4	    baseURL: '/api/v1',
5	    timeout: 30000,
6	    withCredentials: true,
7	    headers: {
8	        'Content-Type': 'application/json',
9	    },
10	});
11	
12	const AUTH_ERROR_CODE = 'AUTH_1002';
13	let unauthorizedHandler = null;
14	
15	const isUnauthorized = (status, code) => status === 401 || code === AUTH_ERROR_CODE;
16	
17	const expireServerSession = () => {
18	    void axios.post('/api/v1/auth/logout', null, { withCredentials: true }).catch(() => {});
19	};
20	
21	export const setUnauthorizedHandler = (handler) => {
22	    unauthorizedHandler = handler;
23	};
24	
25	const handleUnauthorized = () => {
26	    // Global auth contract: any 401/AUTH_1002 response clears the local session and asks the server to expire the cookie.
27	    expireServerSession();
28	    unauthorizedHandler?.();
29	};
30	
31	axiosInstance.interceptors.response.use(
32	    (response) => response,
33	    (error) => {
34	        const status = error.response?.status;
35	        const code = error.response?.data?.code;
36	
37	        if (isUnauthorized(status, code)) {
38	            handleUnauthorized();
39	        }
40	
41	        return Promise.reject(error);
42	    }
43	);
44	
45	/**
46	 * @template T
47	 * @param {{data?: {success?: boolean, data?: T, message?: string} | null} | null | undefined} response
48	 * @returns {T}
49	 */
50	export const unwrapResponse = (response) => {
51	    const data = response?.data;
52	
53	    if (data === null || data === undefined) {
54	        throw new Error('요청 처리에 실패했습니다.');
55	    }
56	
57	    const isSuccess = data.success === true;
58	    const hasPayload = data.data !== null && data.data !== undefined;
59	
60	    if (!isSuccess || !hasPayload) {
61	        throw new Error(data.message ?? '요청 처리에 실패했습니다.');
62	    }
63	
64	    return data.data;
65	};
