3	export const emptyToNull = (value) => {
4	    const next = `${value ?? ''}`.trim();
5	    return next.length ? next : null;
6	};
7	
8	export const toSnakeCase = (value) => {
9	    const hasValue = value !== null && value !== undefined;
10	
11	    if (!hasValue) {
12	        return '';
13	    }
14	
15	    return `${value}`.replace(/[A-Z]/g, (match) => `_${match.toLowerCase()}`);
16	};
17	
18	/**
19	 * @template T
20	 * @param {{ method: string, url: string, data?: unknown, signal?: AbortSignal }} options
21	 * @returns {Promise<T>}
22	 */
23	export async function requestJson({ method, url, data, signal }) {
24	    const response = await axiosInstance.request({
25	        method,
26	        url,
27	        data,
28	        signal,
29	    });
30	
31	    return unwrapResponse(response);
32	}
